import React, { useEffect } from 'react'
import Script from 'next/script'

import type { GTMParams } from '../types/google'

let currDataLayerName = 'dataLayer'

export function GoogleTagManager(props: GTMParams) {
  const {
    gtmId,
    gtmScriptUrl,
    dataLayerName = 'dataLayer',
    auth,
    preview,
    dataLayer,
    nonce,
  } = props

  currDataLayerName = dataLayerName

  const scriptUrl = new URL(
    gtmScriptUrl || 'https://www.googletagmanager.com/gtm.js'
  )
  if (gtmId) {
    scriptUrl.searchParams.set('id', gtmId)
  }
  if (dataLayerName !== 'dataLayer') {
    scriptUrl.searchParams.set('l', dataLayerName)
  }
  if (auth) {
    scriptUrl.searchParams.set('gtm_auth', auth)
  }
  if (preview) {
    scriptUrl.searchParams.set('gtm_preview', preview)
    scriptUrl.searchParams.set('gtm_cookies_win', 'x')
  }

  useEffect(() => {
    // performance.mark is being used as a feature use signal. While it is traditionally used for performance
    // benchmarking it is low overhead and thus considered safe to use in production and it is a widely available
    // existing API.
    // The performance measurement will be handled by Chrome Aurora

    performance.mark('mark_feature_usage', {
      detail: {
        feature: 'next-third-parties-gtm',
      },
    })
  }, [])

  return (
    <>
      <Script
        id="_next-gtm-init"
        dangerouslySetInnerHTML={{
          __html: `
      (function(w,l){
        w[l]=w[l]||[];
        w[l].push({'gtm.start': new Date().getTime(),event:'gtm.js'});
        ${dataLayer ? `w[l].push(${JSON.stringify(dataLayer)})` : ''}
      })(window,'${dataLayerName}');`,
        }}
        nonce={nonce}
      />
      <Script
        id="_next-gtm"
        data-ntpc="GTM"
        src={scriptUrl.href}
        nonce={nonce}
      />
    </>
  )
}

export const sendGTMEvent = (data: Object, dataLayerName?: string) => {
  // special case if we are sending events before GTM init and we have custom dataLayerName
  const dataLayer = dataLayerName || currDataLayerName
  // define dataLayer so we can still queue up events before GTM init
  window[dataLayer] = window[dataLayer] || []
  window[dataLayer].push(data)
}

import postcss from "postcss"
import selectorParser, {
  type ClassName,
  type Selector as SelectorNodeRoot,
} from "postcss-selector-parser"
import { z } from "zod"

const CN_PREFIX = "cn-"

export const styleMapSchema = z.record(
  z.string().startsWith(CN_PREFIX),
  z.string()
)

export type StyleMap = z.infer<typeof styleMapSchema>

export function createStyleMap(input: string) {
  const root = postcss.parse(input)

  const result: Record<string, string> = {}

  root.walkRules((rule) => {
    const selectors = rule.selectors ?? []

    if (selectors.length === 0) {
      return
    }

    const tailwindClasses = extractTailwindClasses(rule)

    if (!tailwindClasses) {
      return
    }

    for (const selector of selectors) {
      const normalizedSelector = normalizeSelector(selector)

      selectorParser((selectorsRoot) => {
        selectorsRoot.each((sel) => {
          const targetClass = findSubjectClass(sel)

          if (!targetClass) {
            return
          }

          const className = targetClass.value

          if (!className.startsWith(CN_PREFIX)) {
            return
          }

          result[className] = result[className]
            ? `${tailwindClasses} ${result[className]}`
            : tailwindClasses
        })
      }).processSync(normalizedSelector)
    }
  })

  return styleMapSchema.parse(result)
}

function normalizeSelector(selector: string) {
  return selector.replace(/\s*&\s*/g, "").trim()
}

function extractTailwindClasses(rule: postcss.Rule) {
  const classes: string[] = []

  for (const node of rule.nodes || []) {
    if (node.type === "atrule" && node.name === "apply") {
      const value = node.params.trim()
      if (value) {
        classes.push(value)
      }
    }
  }

  if (classes.length === 0) {
    return null
  }

  return classes.join(" ")
}

function findSubjectClass(selector: SelectorNodeRoot) {
  const classNodes: ClassName[] = []

  selector.walkClasses((classNode) => {
    if (classNode.value.startsWith(CN_PREFIX)) {
      classNodes.push(classNode)
    }
  })

  if (classNodes.length === 0) {
    return null
  }

  return classNodes[classNodes.length - 1]
}

import type { API, FileInfo } from 'jscodeshift'
import { createParserFromPath } from '../lib/parser'

export default function transformer(file: FileInfo, _api: API) {
  // Run on App Router page/layout/route files, except for test environment.
  if (
    process.env.NODE_ENV !== 'test' &&
    !/[/\\]app[/\\](?:.*[/\\])?(page|layout|route)(\.[^/\\]*)?$/.test(file.path)
  ) {
    return file.source
  }

  const j = createParserFromPath(file.path)
  const root = j(file.source)

  let hasChanges = false

  // Remove export const experimental_ppr = boolean
  const directExports = root.find(j.ExportNamedDeclaration, {
    declaration: {
      type: 'VariableDeclaration',
      declarations: [
        {
          id: { name: 'experimental_ppr' },
        },
      ],
    },
  })

  if (directExports.size() > 0) {
    directExports.remove()
    hasChanges = true
  }

  // Remove const experimental_ppr = boolean declarations
  const variableDeclarations = root.find(j.VariableDeclaration).filter((path) =>
    path.node.declarations.some((decl) => {
      if (j.VariableDeclarator.check(decl) && j.Identifier.check(decl.id)) {
        return decl.id.name === 'experimental_ppr'
      }
      return false
    })
  )

  if (variableDeclarations.size() > 0) {
    variableDeclarations.remove()
    hasChanges = true
  }

  // Handle export { experimental_ppr } and export { experimental_ppr, other }
  const namedExports = root
    .find(j.ExportNamedDeclaration)
    .filter((path) => path.node.specifiers && path.node.specifiers.length > 0)

  namedExports.forEach((path) => {
    const specifiers = path.node.specifiers
    if (!specifiers) return

    const filteredSpecifiers = specifiers.filter((spec) => {
      if (j.ExportSpecifier.check(spec) && j.Identifier.check(spec.local)) {
        return spec.local.name !== 'experimental_ppr'
      }
      return true
    })

    // If we removed any specifiers
    if (filteredSpecifiers.length !== specifiers.length) {
      hasChanges = true

      // If no specifiers left, remove the entire export statement
      if (filteredSpecifiers.length === 0) {
        j(path).remove()
      } else {
        // Update the specifiers array
        path.node.specifiers = filteredSpecifiers
      }
    }
  })

  if (hasChanges) {
    return root.toSource()
  }

  return file.source
}

import { test as base, defineConfig } from './index'
import type { NextFixture } from './next-fixture'
// eslint-disable-next-line import/no-extraneous-dependencies
import { type RequestHandler, handleRequest } from 'msw'
// eslint-disable-next-line import/no-extraneous-dependencies
import { Emitter } from 'strict-event-emitter'

// eslint-disable-next-line import/no-extraneous-dependencies
export * from 'msw'
export * from '@playwright/test'
export type { NextFixture }
export { defineConfig }

export interface MswFixture {
  use: (...handlers: RequestHandler[]) => void
}

export const test = base.extend<{
  msw: MswFixture
  mswHandlers: RequestHandler[]
}>({
  mswHandlers: [[], { option: true }],

  msw: [
    async ({ next, mswHandlers }, use) => {
      const handlers: RequestHandler[] = [...mswHandlers]
      const emitter = new Emitter()

      next.onFetch(async (request) => {
        const requestId = Math.random().toString(16).slice(2)
        let isUnhandled = false
        let isPassthrough = false
        let mockedResponse
        await handleRequest(
          request.clone(),
          requestId,
          handlers.slice(0),
          {
            onUnhandledRequest: () => {
              isUnhandled = true
            },
          },
          emitter as any,
          {
            onPassthroughResponse: () => {
              isPassthrough = true
            },
            onMockedResponse: (r) => {
              mockedResponse = r
            },
          }
        )

        if (isUnhandled) {
          return undefined
        }
        if (isPassthrough) {
          return 'continue'
        }

        if (mockedResponse) {
          return mockedResponse
        }

        return 'abort'
      })

      await use({
        use: (...newHandlers) => {
          handlers.unshift(...newHandlers)
        },
      })

      handlers.length = 0
    },
    { auto: true },
  ],
})

export default test

import { promises } from 'fs'
import { bold, cyan, red } from './picocolors'

import path from 'path'
import { hasNecessaryDependencies } from './has-necessary-dependencies'
import type { NecessaryDependencies } from './has-necessary-dependencies'
import { fileExists, FileType } from './file-exists'
import * as Log from '../build/output/log'
import { getPkgManager } from './helpers/get-pkg-manager'

async function missingDependencyError(dir: string) {
  const packageManager = getPkgManager(dir)

  throw new Error(
    bold(
      red(
        "It looks like you're trying to use Partytown with next/script but do not have the required package(s) installed."
      )
    ) +
      '\n\n' +
      bold(`Please install Partytown by running:`) +
      '\n\n' +
      `\t${bold(
        cyan(
          (packageManager === 'yarn'
            ? 'yarn add --dev'
            : packageManager === 'pnpm'
              ? 'pnpm install --save-dev'
              : 'npm install --save-dev') + ' @builder.io/partytown'
        )
      )}` +
      '\n\n' +
      bold(
        `If you are not trying to use Partytown, please disable the experimental ${cyan(
          '"nextScriptWorkers"'
        )} flag in next.config.js.`
      ) +
      '\n'
  )
}

async function copyPartytownStaticFiles(
  deps: NecessaryDependencies,
  staticDir: string
) {
  const partytownLibDir = path.join(staticDir, '~partytown')
  const hasPartytownLibDir = await fileExists(
    partytownLibDir,
    FileType.Directory
  )

  if (hasPartytownLibDir) {
    await promises.rm(partytownLibDir, { recursive: true, force: true })
  }

  const { copyLibFiles } = await Promise.resolve(
    require(path.join(deps.resolved.get('@builder.io/partytown')!, '../utils'))
  )

  await copyLibFiles(partytownLibDir)
}

export async function verifyPartytownSetup(
  dir: string,
  targetDir: string
): Promise<void> {
  const partytownDeps: NecessaryDependencies = hasNecessaryDependencies(dir, [
    {
      file: '@builder.io/partytown',
      pkg: '@builder.io/partytown',
      exportsRestrict: false,
    },
  ])

  if (partytownDeps.missing?.length > 0) {
    await missingDependencyError(dir)
  } else {
    try {
      await copyPartytownStaticFiles(partytownDeps, targetDir)
    } catch (err) {
      Log.warn(
        `Partytown library files could not be copied to the static directory. Please ensure that ${bold(
          cyan('@builder.io/partytown')
        )} is installed as a dependency.`
      )
    }
  }
}

// Adapted from https://github.com/vercel/next.js/blob/canary/packages/next/src/client/dev/error-overlay/websocket.ts

import type { HmrMessage } from '@vercel/turbopack-ecmascript-runtime/browser/dev/hmr-client/hmr-client'

let source: WebSocket
const messageCallbacks: ((message: HmrMessage) => void)[] = []

// TODO: add timeout again
// let lastActivity = Date.now()

function getSocketProtocol(assetPrefix: string): string {
  let protocol = location.protocol

  try {
    // assetPrefix is a url
    protocol = new URL(assetPrefix).protocol
  } catch (_) {}

  return protocol === 'http:' ? 'ws' : 'wss'
}

export function addMessageListener(cb: (message: HmrMessage) => void) {
  messageCallbacks.push(cb)
}

export function sendMessage(data: any) {
  if (!source || source.readyState !== source.OPEN) return
  return source.send(data)
}

export type HMROptions = {
  path: string
  assetPrefix: string
  timeout?: number
  log?: boolean
}

// This is not used by Next.js, but it is used by the standalone turbopack-cli
export function connectHMR(options: HMROptions) {
  const { timeout = 5 * 1000 } = options

  function init() {
    if (source) source.close()

    console.log('[HMR] connecting...')

    function handleOnline() {
      const connected = { type: 'turbopack-connected' as const }
      messageCallbacks.forEach((cb) => {
        cb(connected)
      })

      if (options.log) console.log('[HMR] connected')
      // lastActivity = Date.now()
    }

    function handleMessage(event: MessageEvent) {
      // lastActivity = Date.now()

      const message = {
        type: 'turbopack-message' as const,
        data: JSON.parse(event.data),
      }
      messageCallbacks.forEach((cb) => {
        cb(message)
      })
    }

    // let timer: NodeJS.Timeout

    function handleDisconnect() {
      source.close()
      setTimeout(init, timeout)
    }

    const { hostname, port } = location
    const protocol = getSocketProtocol(options.assetPrefix || '')
    const assetPrefix = options.assetPrefix.replace(/^\/+/, '')

    let url = `${protocol}://${hostname}:${port}${
      assetPrefix ? `/${assetPrefix}` : ''
    }`

    if (assetPrefix.startsWith('http')) {
      url = `${protocol}://${assetPrefix.split('://')[1]}`
    }

    source = new window.WebSocket(`${url}${options.path}`)
    source.onopen = handleOnline
    source.onerror = handleDisconnect
    source.onmessage = handleMessage
  }

  init()
}

import type { API, FileInfo } from 'jscodeshift'
import { createParserFromPath } from '../lib/parser'

export default function transformer(file: FileInfo, _api: API) {
  const j = createParserFromPath(file.path)
  const root = j(file.source)

  // Find the metadata export
  const metadataExport = root.find(j.ExportNamedDeclaration, {
    declaration: {
      type: 'VariableDeclaration',
      declarations: [
        {
          id: { name: 'metadata' },
        },
      ],
    },
  })

  if (metadataExport.size() !== 1) {
    return file.source
  }

  const metadataObject = metadataExport.find(j.ObjectExpression).get(0).node
  if (!metadataObject) {
    console.error('Could not find metadata object')
    return file.source
  }

  let metadataProperties = metadataObject.properties
  let viewportProperties
  let hasChanges = false

  const viewport = metadataProperties.find(
    (prop) => prop.key.name === 'viewport'
  )
  if (viewport) {
    viewportProperties = viewport.value.properties
    metadataProperties = metadataProperties.filter(
      (prop) => prop.key.name !== 'viewport'
    )
    hasChanges = true
  } else {
    viewportProperties = []
  }

  const colorScheme = metadataProperties.find(
    (prop) => prop.key.name === 'colorScheme'
  )
  if (colorScheme) {
    viewportProperties.push(colorScheme)
    metadataProperties = metadataProperties.filter(
      (prop) => prop.key.name !== 'colorScheme'
    )
    hasChanges = true
  }

  const themeColor = metadataProperties.find(
    (prop) => prop.key.name === 'themeColor'
  )
  if (themeColor) {
    viewportProperties.push(themeColor)
    metadataProperties = metadataProperties.filter(
      (prop) => prop.key.name !== 'themeColor'
    )
    hasChanges = true
  }

  // Only apply changes if there were actual modifications
  if (!hasChanges) {
    return file.source
  }

  // Update the metadata export
  metadataExport
    .find(j.ObjectExpression)
    .replaceWith(j.objectExpression(metadataProperties))

  // Create the new viewport object
  const viewportExport = j.exportNamedDeclaration(
    j.variableDeclaration('const', [
      j.variableDeclarator(
        j.identifier('viewport'),
        j.objectExpression(viewportProperties)
      ),
    ])
  )

  // Append the viewport export to the body of the program
  if (viewportProperties.length) {
    root.get().node.program.body.push(viewportExport)
  }

  return root.toSource()
}

import fs from 'fs/promises';
import fsPath from 'path';
import type ExtractorCodec from '../format/ExtractorCodec.js';
import type {ExtractorMessage, Locale} from '../types.js';

export default class CatalogPersister {
  private messagesPath: string;
  private codec: ExtractorCodec;
  private extension: string;

  public constructor(params: {
    messagesPath: string;
    codec: ExtractorCodec;
    extension: string;
  }) {
    this.messagesPath = params.messagesPath;
    this.codec = params.codec;
    this.extension = params.extension;
  }

  private getFileName(locale: Locale): string {
    return locale + this.extension;
  }

  private getFilePath(locale: Locale): string {
    return fsPath.join(this.messagesPath, this.getFileName(locale));
  }

  public async read(locale: Locale): Promise<Array<ExtractorMessage>> {
    const filePath = this.getFilePath(locale);
    let content: string;
    try {
      content = await fs.readFile(filePath, 'utf8');
    } catch (error) {
      if (
        error &&
        typeof error === 'object' &&
        'code' in error &&
        error.code === 'ENOENT'
      ) {
        return [];
      }
      throw new Error(
        `Error while reading ${this.getFileName(locale)}:\n> ${error}`,
        {cause: error}
      );
    }
    try {
      return this.codec.decode(content, {locale});
    } catch (error) {
      throw new Error(
        `Error while decoding ${this.getFileName(locale)}:\n> ${error}`,
        {cause: error}
      );
    }
  }

  public async write(
    messages: Array<ExtractorMessage>,
    context: {
      locale: Locale;
      sourceMessagesById: Map<string, ExtractorMessage>;
    }
  ): Promise<void> {
    const filePath = this.getFilePath(context.locale);
    const content = this.codec.encode(messages, context);

    try {
      const outputDir = fsPath.dirname(filePath);
      await fs.mkdir(outputDir, {recursive: true});
      await fs.writeFile(filePath, content);
    } catch (error) {
      console.error(`❌ Failed to write catalog: ${error}`);
    }
  }

  public async getLastModified(locale: Locale): Promise<Date | undefined> {
    const filePath = this.getFilePath(locale);
    try {
      const stats = await fs.stat(filePath);
      return stats.mtime;
    } catch {
      return undefined;
    }
  }
}

import { createTransformer } from '../lib/create-transformer';

export default createTransformer((fileInfo, api, options, context) => {
  const { j, root } = context;

  // Replace imports
  root
    .find(j.ImportDeclaration)
    .filter(path => path.node.source.value === 'ai')
    .forEach(path => {
      const newSpecifiers = path.node.specifiers
        ?.map(spec => {
          if (spec.type !== 'ImportSpecifier') return spec;

          const oldName = spec.imported.name;
          if (oldName === 'experimental_createModelRegistry') {
            context.hasChanges = true;
            return j.importSpecifier(
              j.identifier('experimental_createProviderRegistry'),
            );
          }

          if (
            [
              'experimental_Provider',
              'experimental_ProviderRegistry',
              'experimental_ModelRegistry',
            ].includes(oldName)
          ) {
            context.hasChanges = true;
            return j.importSpecifier(j.identifier('Provider'));
          }

          return spec;
        })
        .filter((spec, index, arr) => {
          // Deduplicate specifiers
          if (!spec) return false;
          return (
            arr.findIndex(
              s =>
                s?.type === 'ImportSpecifier' &&
                spec.type === 'ImportSpecifier' &&
                s.imported.name === spec.imported.name,
            ) === index
          );
        });

      path.node.specifiers = newSpecifiers;
    });

  // Replace type references
  root
    .find(j.TSTypeReference)
    .filter(
      path =>
        path.node.typeName.type === 'Identifier' &&
        [
          'experimental_Provider',
          'experimental_ProviderRegistry',
          'experimental_ModelRegistry',
        ].includes(path.node.typeName.name),
    )
    .forEach(path => {
      context.hasChanges = true;
      path.node.typeName = j.identifier('Provider');
    });

  // Replace function calls
  root
    .find(j.CallExpression, {
      callee: {
        type: 'Identifier',
        name: 'experimental_createModelRegistry',
      },
    })
    .forEach(path => {
      context.hasChanges = true;
      path.node.callee = j.identifier('experimental_createProviderRegistry');
    });
});

import type { Command, Help } from 'next/dist/compiled/commander'
import { bold } from '../lib/picocolors'

// Copy-pasted from Commander's Help class -> formatHelp().
// TL;DR, we're overriding the built-in help to add a few niceties.
// Link: https://github.com/tj/commander.js/blob/master/lib/help.js
const formatCliHelpOutput = (cmd: Command, helper: Help) => {
  const termWidth = helper.padWidth(cmd, helper)
  const helpWidth = helper.helpWidth || 80
  const itemIndentWidth = 2
  const itemSeparatorWidth = 2 // between term and description

  function formatItem(term: string, description: string) {
    let value = term

    if (description) {
      if (term === 'directory') {
        value = `[${term}]`
      }

      const fullText = `${value.padEnd(
        termWidth + itemSeparatorWidth
      )}${description}`

      return helper.wrap(
        fullText,
        helpWidth - itemIndentWidth,
        termWidth + itemSeparatorWidth
      )
    }

    return term
  }

  function formatList(textArray: string[]) {
    return textArray.join('\n').replace(/^/gm, ' '.repeat(itemIndentWidth))
  }

  // Usage
  let output = [`${bold('Usage:')} ${helper.commandUsage(cmd)}`, '']

  // Description
  const commandDescription = helper.commandDescription(cmd)

  if (commandDescription.length > 0) {
    output = output.concat([helper.wrap(commandDescription, helpWidth, 0), ''])
  }

  // Arguments
  const argumentList = helper.visibleArguments(cmd).map((argument) => {
    return formatItem(
      helper.argumentTerm(argument),
      helper.argumentDescription(argument)
    )
  })

  if (argumentList.length > 0) {
    output = output.concat([
      `${bold('Arguments:')}`,
      formatList(argumentList),
      '',
    ])
  }

  // Options
  const optionList = helper.visibleOptions(cmd).map((option) => {
    return formatItem(
      helper.optionTerm(option),
      helper.optionDescription(option)
    )
  })

  if (optionList.length > 0) {
    output = output.concat([`${bold('Options:')}`, formatList(optionList), ''])
  }

  // Commands
  const commandList = helper.visibleCommands(cmd).map((subCmd) => {
    return formatItem(
      helper.subcommandTerm(subCmd),
      helper.subcommandDescription(subCmd)
    )
  })

  if (commandList.length > 0) {
    output = output.concat([
      `${bold('Commands:')}`,
      formatList(commandList),
      '',
    ])
  }

  return output.join('\n')
}

export { formatCliHelpOutput }

